    pub fn parse_swap_market(&self, mut market: Value) -> Value {
        //
        //            {
        //                "symbol": "BNB_USDT_PERP",
        //                "bAsset": ".PBNBUSDT",
        //                "bCcy": "BNB",
        //                "qCcy": "USDT",
        //                "visibleStartTime": "1620390600000",
        //                "tradableStartTime": "1620390600000",
        //                "sCcy": "USDT",
        //                "tSz": "0.001",
        //                "pxScale": "0.001,0.01,0.1,1,10",
        //                "lotSz": "1",
        //                "minSz": "1",
        //                "ctVal": "0.1",
        //                "status": "OPEN",
        //                "oDate": "1620287590000",
        //                "maxPx": "1000000",
        //                "minPx": "0.001",
        //                "maxQty": "1000000",
        //                "minQty": "1",
        //                "maxLever": "50",
        //                "lever": "10",
        //                "ctType": "LINEAR",
        //                "alias": "",
        //                "iM": "0.02",
        //                "mM": "0.0115",
        //                "mR": "2000",
        //                "buyLmt": "",
        //                "sellLmt": "",
        //                "ordPxRange": "0.05",
        //                "marketMaxQty": "2800",
        //                "limitMaxQty": "1000000"
        //            },
        //
        let mut id: Value = self.safe_string_k(market.clone(), "symbol", &[]);
        let mut baseId: Value = self.safe_string_k(market.clone(), "bCcy", &[]);
        let mut quoteId: Value = self.safe_string_k(market.clone(), "qCcy", &[]);
        let mut settleId: Value = self.safe_string_k(market.clone(), "sCcy", &[]);
        let mut base: Value = self.safe_currency_code(baseId.clone(), &[]);
        let mut quote: Value = self.safe_currency_code(quoteId.clone(), &[]);
        let mut settle: Value = self.safe_currency_code(settleId.clone(), &[]);
        let mut status: Value = self.safe_string_k(market.clone(), "status", &[]);
        let mut active: Value = Value::Bool(is_equal(&status, &Value::Str("OPEN".to_string())));
        let mut linear: Value = Value::Bool(is_equal(&get_value(&market, &Value::Str("ctType".to_string())), &Value::Str("LINEAR".to_string())));
        let mut symbol: Value = add(&add(&base, &Value::Str("/".to_string())), &quote);
        if is_true(&linear) {
            symbol = add(&symbol, &add(&Value::Str(":".to_string()), &settle));
        }  else {
            // actually, exchange does not have any inverse future now
            symbol = add(&symbol, &add(&Value::Str(":".to_string()), &base));
        }
        let mut alias: Value = self.safe_string_k(market.clone(), "alias", &[]);
        let mut type_var: Value = Value::Str("swap".to_string());
        if !is_equal(&alias, &Value::Null) {
            type_var = Value::Str("future".to_string());
        }
        let mut marketType: Value = ternary(is_true(&(is_equal(&type_var, &Value::Str("future".to_string())))), Value::Str("future".to_string()), Value::Str("swap".to_string()));
        return Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("id".to_string(), id.clone());
        m.insert("symbol".to_string(), symbol.clone());
        m.insert("base".to_string(), base.clone());
        m.insert("quote".to_string(), quote.clone());
        m.insert("settle".to_string(), settle.clone());
        m.insert("baseId".to_string(), baseId.clone());
        m.insert("quoteId".to_string(), quoteId.clone());
        m.insert("settleId".to_string(), settleId.clone());
        m.insert("type".to_string(), marketType.clone());
        m.insert("spot".to_string(), Value::Bool(false));
        m.insert("margin".to_string(), Value::Bool(false));
        m.insert("swap".to_string(), Value::Bool(is_equal(&type_var, &Value::Str("swap".to_string()))));
        m.insert("future".to_string(), Value::Bool(is_equal(&type_var, &Value::Str("future".to_string()))));
        m.insert("option".to_string(), Value::Bool(false));
        m.insert("active".to_string(), active.clone());
        m.insert("contract".to_string(), Value::Bool(true));
        m.insert("linear".to_string(), linear.clone());
        m.insert("inverse".to_string(), Value::Bool(!is_true(&linear)));
        m.insert("contractSize".to_string(), self.safe_number_k(market.clone(), "ctVal", &[]));
        m.insert("expiry".to_string(), Value::Null);
        m.insert("expiryDatetime".to_string(), Value::Null);
        m.insert("strike".to_string(), Value::Null);
        m.insert("optionType".to_string(), Value::Null);
        m.insert("taker".to_string(), self.safe_number_k(market.clone(), "tFee", &[]));
        m.insert("maker".to_string(), self.safe_number_k(market.clone(), "mFee", &[]));
        m.insert("precision".to_string(), Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("amount".to_string(), self.safe_number_k(market.clone(), "lotSz", &[]));
        m.insert("price".to_string(), self.safe_number_k(market.clone(), "tSz", &[]));
    m
}));
        m.insert("limits".to_string(), Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("amount".to_string(), Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("min".to_string(), self.safe_number_k(market.clone(), "minSz", &[]));
        m.insert("max".to_string(), self.safe_number_k(market.clone(), "limitMaxQty", &[]));
    m
}));
        m.insert("price".to_string(), Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("min".to_string(), self.safe_number_k(market.clone(), "minPx", &[]));
        m.insert("max".to_string(), self.safe_number_k(market.clone(), "maxPx", &[]));
    m
}));
        m.insert("cost".to_string(), Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("min".to_string(), Value::Null);
        m.insert("max".to_string(), Value::Null);
    m
}));
        m.insert("leverage".to_string(), Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("max".to_string(), self.safe_number_k(market.clone(), "maxLever", &[]));
        m.insert("min".to_string(), Value::Null);
    m
}));
    m
}));
        m.insert("created".to_string(), self.safe_integer_k(market.clone(), "oDate", &[]));
        m.insert("info".to_string(), market.clone());
    m
});

    Value::Null
}

